class Board:
    def __init__(self):
        self.reset()

    def reset(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.place_pieces()
        self.kings = []

    def place_pieces(self):
        # Place black pieces
        for i in range(0, 3):
            for j in (1 if i % 2 == 0 else 0):
                self.board[i, j] = -1

        # Place white pieces
        for i in range(5, 8):
            for j in (0 if i % 2 == 0 else 1):
                self.board[i, j] = 1

    def move_piece(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            piece = self.board[from_pos]
            self.board[from_pos] = 0
            self.board[to_pos] = piece
            if self.check_king(to_pos):
                self.kings.append(to_pos)
            return True
        return False

    def check_king(self, position):
        color = np.sign(self.board[position])
        row = position[0]
        if (color == -1 and row == 0) or (color == 1 and row == 7):
            return True
        return False

    def capture_pieces(self, positions):
        for pos in positions:
            self.board[pos] = 0

    def get_jumps(self, position, board=None):
        if board is None:
            board = self.board
        jumps = []
        piece = board[position]
        color = np.sign(piece)
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dx, dy in directions:
            j_pos = (position[0] + 2 * dx, position[1] + 2 * dy)
            if 0 <= j_pos[0] < 8 and 0 <= j_pos[1] < 8:
                if board[j_pos] == -color:
                    p_pos = (position[0] + dx, position[1] + dy)
                    if 0 <= p_pos[0] < 8 and 0 <= p_pos[1] < 8 and board[p_pos] == 0:
                        jumps.append((j_pos, p_pos))
        return jumps

    def check_win(self, player_index):
        color = -1 if player_index == 0 else 1
        return all(np.sign(piece) != color for piece in self.board.flatten() if piece != 0)

    def __str__(self):
        board_str = "  a b c d e f g h\n"
        for i in range(8):
            board_str += f"{i+1} | "
            for j in range(8):
                if self.board[i, j] == -1:
                    board_str += "X "
                elif self.board[i, j] == 1:
                    board_str += "O "
                else:
                    board_str += ". "
            board_str += "| " + str(i+1) + "\n"
        return board_str
