    def capture_piece(self, pos1, pos2):
        row_diff = abs(pos2[0] - pos1[0])
        col_diff = abs(pos2[1] - pos1[1])

        intermediate_pos = [(pos1[0] + (direction * i), pos1[1] + i) for i in range(1, row_diff)]

        for pos, col in intermediate_pos:
            if self.board[pos][col] != '.' and piece.color == self.board[pos2[0]][pos2[1]]:
                self.board[pos] = '.'

    def is_king(self, pos):
