        # Check for winner (either no pieces left or all pieces captured)
        red_pieces = sum(row.count('R') for row in self.board)
        black_pieces = sum(row.count('B') for row in self.board)

        if red_pieces == 0:
            return 'Black wins!'
        elif black_pieces == 0:
            return 'Red wins!'
        else:
